import React, { useState } from "react";
import "./Dashboard.css";

export default function Dashboard({ employee }) {
  // Dashboard page shows only employee data
  return (
    <div className="dash-wrapper" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
      <div style={{ background: '#fff', borderRadius: 16, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', padding: '24px 32px', minWidth: 320, textAlign: 'center' }}>
        <div style={{ fontSize: 22, fontWeight: 700, color: '#0f9d58', marginBottom: 8 }}>
          {employee?.empName || 'Employee Name'}
        </div>
        <div style={{ fontSize: 16, color: '#222', marginBottom: 4 }}>
          <b>ID:</b> {employee?.empId || 'N/A'}
        </div>
        <div style={{ fontSize: 16, color: '#222', marginBottom: 4 }}>
          <b>Department:</b> {employee?.department || 'N/A'}
        </div>
        <div style={{ fontSize: 16, color: '#222' }}>
          <b>Role:</b> {employee?.role || employee?.title || 'N/A'}
        </div>
      </div>
    </div>
  );
}
